Here's the full setup:

**XAML ‚Äî wrap CollectionView in RefreshView:**

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                        <Label Text="{Binding Name}" FontAttributes="Bold" />
                        <Label Text="{Binding Description}"
                               FontSize="12" TextColor="Gray" />
                    </VerticalStackLayout>
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalTextAlignment="Center"
                   VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel (using CommunityToolkit.Mvvm):**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IItemService _itemService;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> items = new();

    [ObservableProperty]
    private Item? selectedItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ItemsViewModel(IItemService itemService, INavigationService nav)
    {
        _itemService = itemService;
        _nav = nav;
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (SelectedItem is null) return;

        await Shell.Current.GoToAsync($"detail?id={SelectedItem.Id}");

        // Clear selection so the user can re-select the same item later
        SelectedItem = null;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _itemService.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            // Must set false or the spinner stays visible
            IsRefreshing = false;
        }
    }
}
```

**Key bindings explained:**

| Property | Binding | Why |
|---|---|---|
| `ItemsSource` | `ObservableCollection<Item>` | Auto-updates UI on add/remove |
| `SelectedItem` | `TwoWay` | VM reads the selection *and* clears it after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires when selection changes ‚Äî triggers navigation |
| `IsRefreshing` | `TwoWay` (default) | RefreshView shows spinner; VM sets `false` when done |
| `Command` | `RefreshCommand` | Fires on pull-to-refresh gesture |

**Important details:**
- Always set `IsRefreshing = false` in a `finally` block ‚Äî otherwise the spinner gets stuck.
- Clear `SelectedItem` after navigation so the same item can be tapped again.
- Update collections on the **UI thread** via `MainThread.BeginInvokeOnMainThread`.
- Use `x:DataType` on `DataTemplate` for compiled bindings (better perf, compile-time checking).
